#include <bits/stdc++.h>
using namespace std;
const int N=100005;
int n,vis[N],cnt,root,ans;
vector<int> g[N];
void dfs(int u,int fa)
{
    for(int i=0;i<g[u].size();i++)
    {
        int v=g[u][i];
        if(v==fa) continue;
        dfs(v,u);
        vis[u]+=vis[v];
    }
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>vis[i];
        if(vis[i])
        {
            cnt++;
            root=i;
        }
    }
    for(int i=1;i<n;i++)
    {
        int x,y;
        cin>>x>>y;
        g[x].push_back(y);
        g[y].push_back(x);
    }
    dfs(root,0);
    for(int i=1;i<=n;i++)
    {
        ans+=bool(vis[i]);
    }
    cout<<(ans-cnt);
    return 0;
}
